def average(nums):
    if len(nums) == 0:
        return None

    total = 0

    for num in nums:
        total = total + num

    return total / len(nums)


numbers = []
result = average(numbers)

if result is None:
    print("平均を計算できません: 数値がありません")
else:
    print("平均:", result)

